var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대략적인 줄거리는 이미 파악하고 있습니다.","JPN":"話の大筋はすでに把握済みです。","ENG":"I am already aware of the general plot.","TWN":"大概的情節我已經明白了。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"프리드웬의 기관장께서는 꽤 일찍부터 저희에게 파편에 대한 조사를 요청하셨거든요.","JPN":"プリドウェンの機関長は、以前から私たちに破片の調査を要請していました。","ENG":"We were requested to conduct an investigation on the Fragment by Prydwen's chief a while ago.","TWN":"普利多溫的機關長很早就請求我們對碎片進行了調查。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서? 성과가 좀 있었어?","JPN":"で？　成果はあったのか？","ENG":"So? Any progress?","TWN":"然後呢？有什麼成果嗎？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 그다지 유의미한 성과는 없었습니다.","JPN":"いいえ。あまり意味のある成果はありませんでした。","ENG":"No. There were not any significant results.","TWN":"沒有，並沒有多少有意義的成果。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"국토 면적이 작다고 해도, 성황청은 엄연히 권력과 위계가 존재하는 독립국가입니다.","JPN":"国土の面積が狭いとはいえ、聖皇庁は厳として権力と位階が存在する独立国家です。","ENG":"Although the size is small, the Holy Curia is still an independent nation where authority and hierarchy exist.","TWN":"雖然國土面積小，但聖皇廳卻也是存在權力和權威的獨立國家。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"겨우 집행사제의 권한으로 접근할 수 있는 정보는 한정되어 있죠.","JPN":"たかが執行司祭の権限では、得られる情報が限られています。","ENG":"There is a limit to the information that an Inquisitorial Priest has access to.","TWN":"僅憑執行祭司的許可權能獲取的情報有限。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"더욱이 그 정보가 <color=#ffd34c>성배</color>와 관련된 것이라면.","JPN":"その情報が<color=#ffd34c>聖杯</color>に関するものとなれば、尚更です。","ENG":"And, if that information has to do with the <color=#ffd34c>Holy Grail</color>,","TWN":"而且，如果該情報與<color=#ffd34c>聖杯</color>有關……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기관과 연결고리인 저에게 성황청은 관련 정보를 넘기려 하지 않을 겁니다.","JPN":"機関と繋がりのある私に、聖皇庁は関連情報を渡そうとしないはずです。","ENG":"the Holy Curia will hold relevant information from me since I'm the link to the Institution.","TWN":"聖皇廳就更不會將相關情報交給與機關有關聯的我。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 하여간 어딜가나 그 놈의 기싸움이 문제라니깐.","JPN":"チッ、いつもそことの睨み合いが邪魔するんだよ。","ENG":"Tsk. It's always a power struggle, isn't it?","TWN":"嘖，怎麼不管到哪裡都要搞這種意氣之爭……"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"However...","TWN":"只是……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"다만?","JPN":"ただ？","ENG":"However?","TWN":"只是？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기적심의회의 전 의장이셨던 요한 니콜라이 3세께서는 버넷 경과 막역한 사이셨습니다.","JPN":"奇跡審議会の元議長であったヨハン・ニコライ3世は、バーネット卿と大変親しい間柄でした。","ENG":"The former chairman of the Miracle Investigation Council, Johan Nicholas III, was close to Sir Burnett.","TWN":"奇蹟議會前議長約翰·尼古拉3世與伯內特卿是莫逆之交。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다시 말해, 성황청 내부에서 파편을 두고 버넷 경과 고고학부장이 갈등을 빚었다면.","JPN":"つまり、聖皇庁の内部で破片をめぐってバーネット卿と考古学部長が対立していたとしたら……","ENG":"In other words, if Sir Burnett and the Dean of Archeology had conflict over the Fragment within the Holy Curia,","TWN":"換句話說，如果是就聖皇廳領土內的碎片問題，伯內特卿和考古學教授產生了矛盾的話。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"십중팔구……. 추기경께서 버넷 경을 지원하셨을 것이라는 맥락을 읽을 수 있겠죠.","JPN":"十中八九……枢機卿はバーネット卿を支持していたでしょう。","ENG":"we can assume the context... that Cardinal Johan would've supported Sir Burnett.","TWN":"十之八九……伯內特卿會得到樞機主教的支持。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇구나!","JPN":"そうか！","ENG":"Okay!","TWN":"原來如此！"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 그 추기경 할배한테 가서 사건에 대해서 물어보면 되겠네!","JPN":"じゃあ、その枢機卿のジジイのところに行って、事件について聞いてみればいいんだ！","ENG":"Then, we should go ask that old Cardinal guy about the incident!","TWN":"那麼，可以去問問那個樞機主教老頭關於案件的事了！"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해 드리죠.","JPN":"喜んで訂正いたします。","ENG":"I would be more than happy to rephrase.","TWN":"請容我糾正一下。\xA0"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서는 지난 불미스러운 사건으로 인해 운명을 달리하셨습니다.","JPN":"猊下は、芳しくない事件によりお亡くなりになりました。","ENG":"His Eminence passed away during the distressing incident in the past.","TWN":"主教因為上次的醜聞，已經離開了人世。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"저런. 고인의 명복을 빌겠네.","JPN":"おっと。それはご冥福をお祈りする。","ENG":"Ahh. May he rest in peace.","TWN":"哎呀，願故人安息。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쯧, 그럼 단서는 여기서 끊어진 건가?","JPN":"チッ、じゃあ手がかりはここで終わりなのか？","ENG":"Tsk. Is this where the trail ends, then?","TWN":"嘖，那線索就這麼斷了？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"같은 맥락에서 기관 분들께서 봐주셨으면 하는 것이 있습니다.","JPN":"実はその繋がりで、機関のみなさんに見ていただきたいものがあります。","ENG":"There is something I would like you to see, in that context.","TWN":"出於同樣的原因，希望機關的各位能幫我看一下。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하의 유품을 정리하면서, 저로서는 이해할 수 없는 문서가 있었거든요.","JPN":"猊下の遺品を整理している途中、私には到底、理解できない文書を見つけたのです。","ENG":"I found an incomprehensible document while I was organizing His Eminence's belongings.","TWN":"在整理主教遺物的時候，我找到了一份令我無法理解的文件。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"문서라고?","JPN":"文書だと？","ENG":"A document?","TWN":"文件？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"열람을 도와드리겠습니다. 자리를 옮기시죠.","JPN":"見ていただけるようでしたら、場所を移しましょう。","ENG":"I will provide access to it. Let us move somewhere else.","TWN":"我給你們看一下，請跟我來。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};